// Extrai bancada_id do tópico: lab/bancada/01/presenca -> "01"
var partes = msg.topic.split("/");
var bancadaId = partes[2];

msg.bancadaId = bancadaId;
msg.payload = parseInt(msg.payload); // converte "0" ou "1" para número

// Salva no contexto global para uso nas regras de negócio
var estado = global.get("estado") || {};
if (!estado[bancadaId]) estado[bancadaId] = {};
estado[bancadaId].presenca = msg.payload;
estado[bancadaId].ultimaPresencaTs = Date.now();

// Atualiza timestamp de ausência contínua
if (msg.payload === 0) {
    if (!estado[bancadaId].inicioAusencia) {
        estado[bancadaId].inicioAusencia = Date.now();
    }
} else {
    // Presença detectada: resetar contador de ausência
    estado[bancadaId].inicioAusencia = null;
}

global.set("estado", estado);

return msg;

var partes = msg.topic.split("/");
var bancadaId = partes[2];

msg.bancadaId = bancadaId;
msg.payload = parseFloat(msg.payload);

var estado = global.get("estado") || {};
if (!estado[bancadaId]) estado[bancadaId] = {};
estado[bancadaId].corrente = msg.payload;
global.set("estado", estado);

return msg;

var partes = msg.topic.split("/");
var bancadaId = partes[2];

msg.bancadaId = bancadaId;
msg.payload = parseFloat(msg.payload);

var estado = global.get("estado") || {};
if (!estado[bancadaId]) estado[bancadaId] = {};
estado[bancadaId].bateria = msg.payload;
global.set("estado", estado);

return msg;

var partes = msg.topic.split("/");
var bancadaId = partes[2];

msg.bancadaId = bancadaId;
msg.payload = parseInt(msg.payload);

var estado = global.get("estado") || {};
if (!estado[bancadaId]) estado[bancadaId] = {};
estado[bancadaId].energizado = msg.payload;
global.set("estado", estado);

return msg;

var campo = msg.topic.split("/")[3];
var valor = parseFloat(msg.payload);

msg.payload = "telemetria,bancada_id=" + msg.bancadaId +
    ",laboratorio_id=lab_01 " +
    campo + "=" + valor +
    " " + Math.floor(Date.now() / 1000);
return msg;

var valorEnergizado = msg.payload;

msg.payload = "status_atuador,bancada_id=" + msg.bancadaId +
    " energizado=" + valorEnergizado +
    " " + Math.floor(Date.now() / 1000);

return msg;

// Verifica se TODAS as bancadas estão sem presença há mais de 10 minutos
var TEMPO_LIMITE_MS = 10 * 60 * 1000; // 10 minutos em ms
var estado = global.get("estado") || {};
var agora = Date.now();

// Verifica se há alguma bancada com presença detectada
var algumOcupado = false;
var bancadasIds = Object.keys(estado);

if (bancadasIds.length === 0) return null; // ainda não recebeu dados

for (var i = 0; i < bancadasIds.length; i++) {
    var b = estado[bancadasIds[i]];
    if (b.presenca === 1) {
        algumOcupado = true;
        break;
    }
}

if (algumOcupado) {
    // Há presença: garante que todas as bancadas estejam energizadas
    // (religamento por detecção de presença)
    var comandos = [];
    for (var j = 0; j < bancadasIds.length; j++) {
        var bid = bancadasIds[j];
        if (estado[bid].energizado === 0) {
            // Estava desligada: religa
            comandos.push({
                payload: "ON",
                topic: "lab/bancada/" + bid + "/comando",
                bancadaId: bid,
                motivo: "presenca_detectada",
                tipo: "religamento"
            });
        }
    }
    if (comandos.length > 0) {
        return [comandos, null]; // saída 1: comandos, saída 2: nenhum evento ainda
    }
    return null;
}

// Nenhuma bancada ocupada: verifica tempo de ausência contínua
var inicioAusenciaGeral = global.get("inicioAusenciaGeral");
if (!inicioAusenciaGeral) {
    global.set("inicioAusenciaGeral", agora);
    return null;
}

var tempoAusenteMs = agora - inicioAusenciaGeral;

if (tempoAusenteMs >= TEMPO_LIMITE_MS) {
    // Chegou no limite: desliga todas as bancadas que ainda estão energizadas
    var acoes = [];
    for (var k = 0; k < bancadasIds.length; k++) {
        var bk = bancadasIds[k];
        if (estado[bk].energizado !== 0) {
            acoes.push({
                payload: "OFF",
                topic: "lab/bancada/" + bk + "/comando",
                bancadaId: bk,
                motivo: "ausencia_excedida",
                tipo: "desligamento",
                duracaoEstadoAnteriorS: Math.round(tempoAusenteMs / 1000)
            });
        }
    }
    // Reseta o contador para não disparar múltiplas vezes
    global.set("inicioAusenciaGeral", null);

    if (acoes.length > 0) {
        return [acoes, null];
    }
}

// Reseta contador de ausência geral quando há presença
if (algumOcupado) {
    global.set("inicioAusenciaGeral", null);
}

return null;

var bancadaId = msg.bancadaId;
var bateria = msg.payload;
var estado = global.get("estado") || {};

if (!estado[bancadaId]) return null;

var energizado = estado[bancadaId].energizado;

// Bateria >= 100%: desliga se ainda estiver energizada
if (bateria >= 100 && energizado !== 0) {
    msg.payload = "OFF";
    msg.topic = "lab/bancada/" + bancadaId + "/comando";
    msg.motivo = "bateria_carregada";
    msg.tipo = "desligamento";
    msg.duracaoEstadoAnteriorS = 0;
    return [msg, null];
}

// Bateria <= 20%: religa se estiver cortada
if (bateria <= 20 && energizado === 0) {
    msg.payload = "ON";
    msg.topic = "lab/bancada/" + bancadaId + "/comando";
    msg.motivo = "bateria_baixa";
    msg.tipo = "religamento";
    msg.duracaoEstadoAnteriorS = 0;
    return [msg, null];
}

return null;

// Suporta tanto msg única quanto array de msgs (regra de ausência gera array)
if (Array.isArray(msg.payload)) {
    // Múltiplos comandos: retorna array para o Node-RED processar individualmente
    return msg.payload.map(function(cmd) {
        return {
            payload: cmd.payload,
            topic: cmd.topic,
            bancadaId: cmd.bancadaId,
            motivo: cmd.motivo,
            tipo: cmd.tipo,
            duracaoEstadoAnteriorS: cmd.duracaoEstadoAnteriorS || 0
        };
    });
}
// Comando único: passa direto
return msg;

var bancadaId = msg.bancadaId || msg.topic.split("/")[2];

msg.payload = "eventos,bancada_id=" + bancadaId +
              ",tipo=" + (msg.tipo || "desligamento") +
              ",motivo=" + (msg.motivo || "desconhecido") +
              " duracao_estado_anterior_s=" + (msg.duracaoEstadoAnteriorS || 0) +
              " " + Math.floor(Date.now() / 1000);
return msg;

// whatsapp-cmb retorna sucesso se não lançou erro
var sucesso = (msg.payload && msg.payload.toString().includes("error")) ? 0 : 1;
var latencia = Date.now() - (msg.inicioRequisicao || Date.now());

msg.payload = "notificacoes,bancada_id=" + (msg.bancadaId || "desconhecido") +
              ",canal=whatsapp" +
              " sucesso=" + sucesso +
              ",http_status=200" +
              ",latencia_ms=" + latencia +
              " " + Math.floor(Date.now() / 1000);
return msg;

if (msg.tipo !== "desligamento") return null;

var bancadaId = msg.bancadaId || msg.topic.split("/")[2];
var motivoTexto = {
    "ausencia_excedida": "Laboratório vazio por mais de 10 minutos",
    "bateria_carregada": "Bateria do notebook atingiu 100%"
};

msg.payload = "⚡ Desligamento Automático\n"
    + "Bancada: " + bancadaId + "\n"
    + "Motivo: " + (motivoTexto[msg.motivo] || msg.motivo) + "\n"
    + "Horário: " + new Date().toLocaleString("pt-BR");

msg.bancadaId = bancadaId;
msg.inicioRequisicao = Date.now();
return msg;
